/// <summary>
/// BIN Qty Status activation - Abhinav
/// </summary>
/// <returns></returns>
public int active()
{
    int ret = next active();

    FormPartControl formpartcontrol = this.formRun().design().controlName("ETGBinQtyAvailable");
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);
    InventTransferLine InventTransferLine = this.cursor();

    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim = InventTransferLine.inventDimTo_RU();
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdim,formpartcontrol);
    }

    return ret;
}
